module top_module(
  input [3:0] obf_A,
  input [3:0] B,
  output reg out_greater,
  output reg out_equal,
  output reg out_less
);always @ (obf_A, B) begin
    if (obf_A > B) begin
      out_greater = 1;
      out_equal = 0;
      out_less = 0;
    end else if (obf_A == B) begin
      out_greater = 0;
      out_equal = 1;
      out_less = 0;
    end else begin
      out_greater = 0;
      out_equal = 0;
      out_less = 1;
    end
  end

endmodule
